.filter-panel{background:#fff;border:1px solid #dc3545;border-radius:8px;padding:10px;margin-bottom:10px;display:none}
.filter-info{background:#ffe0e0;padding:6px 10px;border-radius:4px;font-size:16px;margin-top:8px}
.msg-box{position:fixed;top:10px;left:50%;transform:translateX(-50%);z-index:9999;min-width:300px;max-width:95%;padding:12px 16px;border-radius:8px;box-shadow:0 4px 15px rgba(0,0,0,.2);font-size:15px}
.msg-box.success{background:#28a745;color:#fff}
