function editFile(p){editPath=typeof p==='string'&&p.match(/^[0-9a-f]+$/i)?cDir+'/'+atob(p.match(/../g).map(function(h){return String.fromCharCode(parseInt(h,16))}).join('')):p;var fn=editPath.split('/').pop()||editPath.split('\\').pop();document.getElementById('editorFileName').textContent=fn;fetch('?getFile='+encodeURIComponent(ep(editPath))+'&key='+PASS).then(function(r){return r.text();}).then(function(c){var e=editPath.split('.').pop().toLowerCase();var m={php:'php',js:'javascript',css:'css',html:'html',json:'json',sql:'sql',py:'python',sh:'sh'};editor.session.setMode('ace/mode/'+(m[e]||'text'));editor.setValue(c,-1);var docRoot='<?php echo addslashes(isset($_SERVER['DOCUMENT_ROOT'])?$_SERVER['DOCUMENT_ROOT']:'');?>';var rel=editPath.replace(docRoot,'').replace(/\\/g,'/');if(rel.charAt(0)!=='/')rel='/'+rel;editUrl='<?php echo (isset($_SERVER['HTTPS'])&&$_SERVER['HTTPS']==='on'?'https':'http').'://'.$siteName;?>'+rel;document.getElementById('editorGoLink').href=editUrl;new bootstrap.Modal(document.getElementById('editorModal')).show();});}
