function addFileToList(data){var list=document.getElementById('fileList');var name=data.name||'';var path=data.path||'';var exists=list.querySelector('tr[data-name="'+name+'"]');if(exists){exists.setAttribute('data-size',data.size||0);exists.setAttribute('data-ctime',data.ctime||Math.floor(Date.now()/1000));exists.setAttribute('data-mtime',data.mtime||Math.floor(Date.now()/1000));exists.querySelector('td:nth-child(3)').textContent=fsize(data.size||0);exists.querySelector('td:nth-child(4)').textContent=fdate(data.ctime||Math.floor(Date.now()/1000));exists.querySelector('td:nth-child(5)').textContent=fdate(data.mtime||Math.floor(Date.now()/1000));list.insertBefore(exists,list.firstChild);return;}var tr=document.createElement('tr');tr.setAttribute('data-name',name);tr.setAttribute('data-path',path);tr.setAttribute('data-dir','0');tr.setAttribute('data-size',data.size||0);tr.setAttribute('data-ctime',data.ctime||Math.floor(Date.now()/1000));tr.setAttribute('data-mtime',data.mtime||Math.floor(Date.now()/1000));tr.setAttribute('data-perms',data.perms||'644');var ext=name.split('.').pop().toLowerCase();var iconClass='bi-file-earmark';var iconColor='';var icons={php:'bi-file-code text-info',js:'bi-file-code text-warning',css:'bi-file-code text-primary',html:'bi-file-code text-danger',json:'bi-file-code',txt:'bi-file-text',jpg:'bi-file-image text-success',jpeg:'bi-file-image text-success',png:'bi-file-image text-success',gif:'bi-file-image text-success',mp4:'bi-film text-primary',webm:'bi-film text-primary',mp3:'bi-music-note-beamed text-success',wav:'bi-music-note-beamed text-success',zip:'bi-file-zip text-warning',rar:'bi-file-zip text-warning','7z':'bi-file-zip text-warning',sql:'bi-database text-info',pdf:'bi-file-pdf text-danger'};if(icons[ext]){var parts=icons[ext].split(' ');iconClass=parts[0];iconColor=parts[1]||'';}var ct=data.ctime||Math.floor(Date.now()/1000);var mt=data.mtime||Math.floor(Date.now()/1000);var isZipFile=ext==='zip';var clickAction=isZipFile?"viewZip('"+path.replace(/'/g,"\\'")+"','"+name+"','')":"editFile('"+path.replace(/'/g,"\\'")+"')";tr.innerHTML='<td><input type="checkbox" class="fc" value="'+name+'"></td><td><span class="fname-wrap"><i class="bi '+iconClass+' '+iconColor+'"></i><a href="#" onclick="'+clickAction+';return false;" class="file-link">'+name+'</a></span></td><td>'+fsize(data.size||0)+'</td><td>'+fdate(ct)+'</td><td>'+fdate(mt)+'</td><td>'+(data.perms||'644')+'</td>';list.insertBefore(tr,list.firstChild);tr.oncontextmenu=function(e){e.preventDefault();ctxEl=this;var m=document.getElementById('ctxMenu');m.style.display='block';m.style.left=Math.min(e.pageX,window.innerWidth-160)+'px';m.style.top=Math.min(e.pageY,window.innerHeight-200)+'px';};}
function doUpload(){if(!selectedFilesList.length){showMsg('Dosya seçin!','error');return;}var formData=new FormData();formData.append('action','upload');formData.append('subfolder',document.getElementById('uploadSubfolder').value);for(var i=0;i<selectedFilesList.length;i++)formData.append('files[]',selectedFilesList[i]);document.getElementById('uploadProgress').style.display='block';var bar=document.getElementById('uploadBar');bar.classList.remove('bg-danger');bar.classList.add('bg-success');var xhr=new XMLHttpRequest();xhr.timeout=600000;function upFail(t){bar.classList.remove('bg-success');bar.classList.add('bg-danger');bar.style.width='100%';bar.textContent='Hata';showMsg('Yükleme başarısız: '+t,'error');}xhr.upload.onprogress=function(e){if(e.lengthComputable){var pct=Math.round((e.loaded/e.total)*100);bar.style.width=pct+'%';bar.textContent=pct+'%';}};xhr.onload=function(){if(xhr.status<200||xhr.status>=300){upFail('Sunucu hatası (HTTP '+xhr.status+')');return;}var d;try{d=JSON.parse(xhr.responseText);}catch(err){upFail('Geçersiz sunucu yanıtı (HTTP '+xhr.status+')');return;}if(d.success&&d.uploads&&d.uploads.length){var extra='';d.uploads.forEach(function(u){extra+='<div style="margin-bottom:5px"><strong>Yüklendi: '+u.name+'</strong> — '+fsize(u.size)+' ';if(u.canEdit){extra+='<a href="#" onclick="editFile(\''+u.path.replace(/'/g,"\\'")+'\');return false;">Aç</a> - ';}else if(u.isVideo){extra+='<a href="#" onclick="viewMedia(\''+u.path.replace(/'/g,"\\'")+'\',\'video\');return false;">Oynat</a> - ';}else if(u.isAudio){extra+='<a href="#" onclick="viewMedia(\''+u.path.replace(/'/g,"\\'")+'\',\'audio\');return false;">Oynat</a> - ';}extra+='<a href="'+u.url+'" target="_blank">Git</a></div>';addFileToList(u);});showMsg(d.msg,'success',extra,true);bootstrap.Modal.getInstance(document.getElementById('uploadModal')).hide();document.getElementById('uploadFiles').value='';selectedFilesList=[];renderFileList();document.getElementById('uploadProgress').style.display='none';bar.style.width='0%';}else{upFail(d.msg?d.msg:'Dosya kaydedilemedi (izin veya boyut limiti)');}};xhr.onerror=function(){upFail('Bağlantı hatası');};xhr.ontimeout=function(){upFail('Zaman aşımı');};xhr.onabort=function(){upFail('İşlem iptal edildi');};xhr.open('POST','',true);xhr.send(formData);}
function doUploadUrl(){var raw=document.getElementById('uploadUrlInput').value;var urls=raw.split(/\r?\n/).map(function(u){return u.trim();}).filter(function(u){return u!=='';});if(!urls.length){showMsg('URL girin!','error');return;}document.getElementById('urlProgress').style.display='block';var bar=document.getElementById('urlBar');bar.classList.remove('bg-danger');bar.classList.add('bg-success');bar.style.width='0%';bar.textContent='0%';var pct=0;var intv=setInterval(function(){if(pct<90){pct+=5;bar.style.width=pct+'%';bar.textContent=pct+'%';}},700);function urlFail(t){clearInterval(intv);bar.classList.remove('bg-success');bar.classList.add('bg-danger');bar.style.width='100%';bar.textContent='Hata';showMsg('Yükleme başarısız: '+t,'error');}var params=new URLSearchParams();params.append('action','uploadUrl');params.append('subfolder',document.getElementById('uploadUrlSubfolder').value);urls.forEach(function(u){params.append('urls[]',u);});var xhr=new XMLHttpRequest();xhr.timeout=600000;xhr.open('POST','',true);xhr.setRequestHeader('Content-Type','application/x-www-form-urlencoded');xhr.onload=function(){clearInterval(intv);if(xhr.status<200||xhr.status>=300){urlFail('Sunucu hatası (HTTP '+xhr.status+')');return;}var d;try{d=JSON.parse(xhr.responseText);}catch(err){urlFail('Geçersiz sunucu yanıtı (HTTP '+xhr.status+')');return;}if(d.success&&d.uploads&&d.uploads.length){bar.style.width='100%';bar.textContent='100%';var extra='';d.uploads.forEach(function(u){extra+='<div style="margin-bottom:5px"><strong>Yüklendi: '+u.name+'</strong> — '+fsize(u.size)+' ';if(u.canEdit){extra+='<a href="#" onclick="editFile(\''+u.path.replace(/'/g,"\\'")+'\');return false;">Aç</a> - ';}else if(u.isVideo){extra+='<a href="#" onclick="viewMedia(\''+u.path.replace(/'/g,"\\'")+'\',\'video\');return false;">Oynat</a> - ';}else if(u.isAudio){extra+='<a href="#" onclick="viewMedia(\''+u.path.replace(/'/g,"\\'")+'\',\'audio\');return false;">Oynat</a> - ';}extra+='<a href="'+u.url+'" target="_blank">Git</a>';addFileToList(u);});showMsg(d.msg,'success',extra,true);bootstrap.Modal.getInstance(document.getElementById('uploadModal')).hide();document.getElementById('uploadUrlInput').value='';setTimeout(function(){document.getElementById('urlProgress').style.display='none';bar.style.width='0%';},1000);}else{urlFail(d.msg?d.msg:'URL geçersiz veya dosya indirilemedi');}};xhr.onerror=function(){urlFail('Bağlantı hatası');};xhr.ontimeout=function(){urlFail('Zaman aşımı');};xhr.send(params.toString());}
function viewImage(p){var fn=p.split('/').pop();document.getElementById('imgName').textContent=fn;document.getElementById('imgPreview').src='?viewImg='+encodeURIComponent(ep(p))+'&key='+PASS;document.getElementById('imgDl').href='?dl='+encodeURIComponent(ep(p))+'&key='+PASS;var docRoot='<?php echo addslashes(isset($_SERVER['DOCUMENT_ROOT'])?$_SERVER['DOCUMENT_ROOT']:'');?>';var rel=p.replace(docRoot,'').replace(/\\/g,'/');if(rel.charAt(0)!=='/')rel='/'+rel;document.getElementById('imgGoLink').href='<?php echo (isset($_SERVER['HTTPS'])&&$_SERVER['HTTPS']==='on'?'https':'http').'://'.$siteName;?>'+rel;new bootstrap.Modal(document.getElementById('imageModal')).show();}
