function getZipFileIcon(name){var ext=name.split('.').pop().toLowerCase();var icons={'php':'bi-file-code text-info','js':'bi-file-code text-warning','css':'bi-file-code text-primary','html':'bi-file-code text-danger','htm':'bi-file-code text-danger','json':'bi-file-code','xml':'bi-file-code','txt':'bi-file-text','md':'bi-file-text','jpg':'bi-file-image text-success','jpeg':'bi-file-image text-success','png':'bi-file-image text-success','gif':'bi-file-image text-success','svg':'bi-file-image text-success','webp':'bi-file-image text-success','pdf':'bi-file-pdf text-danger','zip':'bi-file-zip text-warning','rar':'bi-file-zip text-warning','7z':'bi-file-zip text-warning','sql':'bi-database text-info','mp4':'bi-film text-primary','webm':'bi-film text-primary','mov':'bi-film text-primary','mp3':'bi-music-note-beamed text-success','wav':'bi-music-note-beamed text-success','ogg':'bi-music-note-beamed text-success','m4a':'bi-music-note-beamed text-success'};return icons[ext]||'bi-file-earmark';}
function viewZip(p,n,sub){currentZipPath=p;currentZipSub=sub||'';document.getElementById('zipName').textContent=n;document.getElementById('zipFile').value=n;var bc='<a href="#" onclick="viewZip(\''+p.replace(/'/g,"\\'")+'\',\''+n+'\',\'\');return false;"><i class="bi bi-file-zip text-warning"></i> '+n+'</a>';if(sub){var parts=sub.split('/').filter(function(x){return x!=='';});var path='';for(var i=0;i<parts.length;i++){path+=parts[i]+'/';bc+=' / <a href="#" onclick="viewZip(\''+p.replace(/'/g,"\\'")+'\',\''+n+'\',\''+path+'\');return false;">'+parts[i]+'</a>';}}document.getElementById('zipBreadcrumb').innerHTML=bc;fetch('?zipC='+encodeURIComponent(ep(p))+'&key='+PASS+'&zipSub='+encodeURIComponent(sub||'')).then(function(r){return r.json();}).then(function(d){var h='';for(var i=0;i<d.length;i++){var item=d[i];if(item.isDir){h+='<tr style="cursor:pointer" onclick="viewZip(\''+p.replace(/'/g,"\\'")+'\',\''+n+'\',\''+(sub||'')+item.name+'\')"><td><i class="bi bi-folder-fill text-warning"></i> '+item.name+'</td><td>-</td><td>-</td></tr>';}else{h+='<tr><td><i class="bi '+getZipFileIcon(item.name)+'"></i> '+item.name+'</td><td>'+fsize(item.size)+'</td><td>'+fsize(item.comp)+'</td></tr>';}}document.getElementById('zipList').innerHTML=h;if(!bootstrap.Modal.getInstance(document.getElementById('zipModal')))new bootstrap.Modal(document.getElementById('zipModal')).show();});}
