function showRename(){var s=getSel();if(s.length!==1){showMsg('Bir öğe seçin!','error');return;}showPrompt('Yeniden Adlandır','<input type="text" id="newName" class="form-control form-control-sm" value="'+s[0]+'">',function(){var n=document.getElementById('newName').value;if(n)submitForm({action:'rename',oldName:s[0],newName:n});});}
