function clipCut(){var s=getSel();if(!s.length){showMsg('Öğe seçin!','error');return;}submitFormArr({action:'clipCut'},'items',s);}
function clipPaste(){submitForm({action:'clipPaste'});}function clipClear(){submitForm({action:'clipClear'});}function showChmod(){var s=getSel();if(!s.length){showMsg('Öğe seçin!','error');return;}showPrompt('İzinler','<input type="text" id="chmodVal" class="form-control form-control-sm" value="755">',function(){var p=document.getElementById('chmodVal').value;if(p)submitFormArr({action:'chmod',perms:p},'items',s);});}
function showTouch(){var s=getSel();if(!s.length){showMsg('Öğe seçin!','error');return;}var def='';var tr=document.querySelector('tr[data-name="'+s[0]+'"]');if(tr){var mt=tr.getAttribute('data-mtime');def=epochToLocalDatetime(mt);}else{def=epochToLocalDatetime(Math.floor(Date.now()/1000));}showPrompt('Tarih','<input type="datetime-local" id="touchVal" class="form-control form-control-sm" value="'+def+'">',function(){var d=document.getElementById('touchVal').value;submitFormArr({action:'touch',datetime:d},'items',s);});}
function showZipServer(){var s=getSel();if(!s.length){showMsg('Öğe seçin!','error');return;}var siteName='<?php echo $siteName;?>';var defaultName=(s.length===1? (s[0].replace(/\.[^.]+$/,'')+'.zip') : siteName+'.zip');showPrompt('Sunucuya Ziple','<input type="text" id="zipNameIn" class="form-control form-control-sm" value="'+defaultName+'">',function(){var n=document.getElementById('zipNameIn').value;if(n)asyncZipServer(s,n);});}
