function bgDl(u){var f=document.createElement('iframe');f.style.cssText='position:absolute;left:-9999px;width:1px;height:1px;border:0';f.src=u;document.body.appendChild(f);setTimeout(function(){if(f.parentNode)f.parentNode.removeChild(f);},60000);}
function downloadSelected(){var s=getSel();if(!s.length){showMsg('Dosya seçin!','error');return;}var hasDir=false;for(var i=0;i<s.length;i++){var tr=document.querySelector('tr[data-name="'+s[i]+'"]');if(tr&&tr.getAttribute('data-dir')==='1'){hasDir=true;break;}}if(hasDir||s.length>1){var siteName='<?php echo $siteName;?>';var defaultName=(s.length===1? (s[0].replace(/\.[^.]+$/,'')+'.zip') : siteName+'.zip');showPrompt('İndirme İsmi','<input type="text" id="dlZipNameIn2" class="form-control form-control-sm" value="'+defaultName+'">',function(){var n=document.getElementById('dlZipNameIn2').value;if(n)asyncZipDownload(s,n);});}else{for(var j=0;j<s.length;j++){bgDl('?dl='+encodeURIComponent(ep(cDir+'/'+s[j]))+'&key='+PASS);}showMsg('İndirme başlatıldı!','success');}}
function directZip(){var s=getSel();if(!s.length){showMsg('Öğe seçin!','error');return;}var siteName='<?php echo $siteName;?>';var defaultName=(s.length===1? (s[0].replace(/\.[^.]+$/,'')+'.zip') : siteName+'.zip');showPrompt('İndirme İsmi','<input type="text" id="dlZipNameIn" class="form-control form-control-sm" value="'+defaultName+'">',function(){var n=document.getElementById('dlZipNameIn').value;if(n)asyncZipDownload(s,n);});}
function asyncZipDownload(items,zipName){var siteName='<?php echo $siteName;?>';var zn=zipName|| (items.length===1? (items[0].replace(/\.[^.]+$/,'')+'.zip') : siteName+'.zip');showMsg('ZIP hazırlanıyor...','info');var fid='zf'+Date.now();var f=document.createElement('iframe');f.name=fid;f.style.cssText='position:absolute;left:-9999px;width:1px;height:1px;border:0';document.body.appendChild(f);var form=document.createElement('form');form.method='POST';form.action='';form.target=fid;form.style.display='none';var act=document.createElement('input');act.type='hidden';act.name='action';act.value='directZip';form.appendChild(act);var zni=document.createElement('input');zni.type='hidden';zni.name='zipName';zni.value=zn;form.appendChild(zni);for(var i=0;i<items.length;i++){var inp=document.createElement('input');inp.type='hidden';inp.name='items[]';inp.value=items[i];form.appendChild(inp);}document.body.appendChild(form);form.submit();document.body.removeChild(form);setTimeout(function(){showMsg('İndirme başlatıldı!','success');},500);setTimeout(function(){if(f.parentNode)f.parentNode.removeChild(f);},120000);}
function asyncZipServer(items,zipName){showMsg('Sunucuya zipleniyor: '+zipName,'info');var body='action=zip&zipName='+encodeURIComponent(zipName);for(var i=0;i<items.length;i++){body+='&items[]='+encodeURIComponent(items[i]);}fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:body}).then(function(r){return r.json();}).then(function(d){if(d.success){showMsg('ZIP olusturuldu: '+zipName,'success');addFileToList({name:d.name,path:d.path,size:d.size,ctime:d.ctime,mtime:d.mtime,perms:d.perms});}else{showMsg('Hata: '+(d.error||'Bilinmeyen hata'),'error');}});}
function unzipSelected(){var s=getSel();if(s.length!==1){showMsg('Bir ZIP seçin!','error');return;}if(!confirm(s[0]+' çıkarılacak?'))return;submitForm({action:'unzip',file:s[0]});}
function submitForm(d){var f=document.createElement('form');f.method='post';for(var k in d)f.innerHTML+='<input type="hidden" name="'+k+'" value="'+d[k]+'">';document.body.appendChild(f);f.submit();}
function submitFormArr(d,n,a){var f=document.createElement('form');f.method='post';for(var k in d)f.innerHTML+='<input type="hidden" name="'+k+'" value="'+d[k]+'">';for(var i=0;i<a.length;i++)f.innerHTML+='<input type="hidden" name="'+n+'[]" value="'+a[i]+'">';document.body.appendChild(f);f.submit();}
function ctxEdit(){if(ctxEl){var p=ctxEl.getAttribute('data-path');var d=ctxEl.getAttribute('data-dir');if(d==='0')editFile(p);else location='?dir='+encodeURIComponent(ep(p))+'&key='+PASS;}}
function ctxRename(){if(ctxEl){var n=ctxEl.getAttribute('data-name');showPrompt('Yeniden Adlandır','<input type="text" id="newName" class="form-control form-control-sm" value="'+n+'">',function(){var nn=document.getElementById('newName').value;if(nn)submitForm({action:'rename',oldName:n,newName:nn});});}}
