function runInfoCollectAll(){var domain=document.getElementById('icaDomain').value;if(!domain){showMsg('Domain veya IP girin!','error');return;}document.getElementById('icaProgressWrap').style.display='block';var bar=document.getElementById('icaProgressBar');var pct=0;var intv=setInterval(function(){if(pct<90){pct+=Math.max(1,Math.round((90-pct)*0.1));bar.style.width=pct+'%';bar.textContent=pct+'%';}},200);document.getElementById('icaOutput').textContent='Sorgulanıyor...';fetch('',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'action=infoCollectAll&domain='+encodeURIComponent(domain)}).then(function(r){return r.json();}).then(function(d){clearInterval(intv);bar.style.width='100%';bar.textContent='100%';renderIcaResult(d);setTimeout(function(){document.getElementById('icaProgressWrap').style.display='none';bar.style.width='0%';},1500);}).catch(function(e){clearInterval(intv);bar.style.width='100%';document.getElementById('icaOutput').textContent='Hata: '+e.message;});}
