document.getElementById('icaIp').textContent=d.ip||'-';document.getElementById('icaCf').textContent=d.cf?'VAR (Korumalı)':'YOK';document.getElementById('icaCf').className='fw-bold '+(d.cf?'text-warning':'text-success');var geo=d.geo||{};var geoTxt=(geo.country||'-')+' / '+(geo.city||'-')+' / '+(geo.isp||geo.org||'-');document.getElementById('icaGeo').textContent=geoTxt;
var out='Hedef: '+d.domain+'\nIP: '+d.ip+(d.is_ip?' (IP sorgusu)':'')+'\nCloudflare: '+(d.cf?'Evet':'Hayır')+'\nÜlke/Şehir/ISP: '+geoTxt+'\n';if(d.rev_total){out+='Reverse IP: '+d.rev_total+' domain\n';}out+='\n';if(d.ssl&&d.ssl.subject){out+='SSL Sertifikası:\n  Subject: '+JSON.stringify(d.ssl.subject)+'\n  Issuer: '+JSON.stringify(d.ssl.issuer||{})+'\n  Geçerli: '+(d.ssl.validFrom||'-')+' - '+(d.ssl.validTo||'-')+'\n';if(d.ssl.san)out+='  SAN: '+d.ssl.san+'\n';out+='\n';}else if(d.ssl&&d.ssl.error){out+='SSL: '+d.ssl.error+'\n\n';}if(d.headers&&Object.keys(d.headers).length){out+='HTTP Headers:\n';Object.keys(d.headers).forEach(function(k){var v=d.headers[k];if(Array.isArray(v))out+='  '+k+': '+v.join(' | ')+'\n';else out+='  '+k+': '+v+'\n';});out+='\n';}out+='Subdomain: Aktif='+(d.subs&&d.subs.active?d.subs.active.length:0)+', Pasif='+(d.subs&&d.subs.passive?d.subs.passive.length:0);document.getElementById('icaOutput').textContent=out;_icaData.genel=out;_icaData.domain=d.domain||'';document.getElementById('icaGenelDlBtn').disabled=false;
var whoisTxt='';if(d.whois){var w=d.whois;whoisTxt='Domain: '+(w.domain||'-')+'\nIP: '+(w.ip||d.ip||'-')+'\n\nKayıtçı: '+(w.registrar||'-')+'\n\nDomain Sahibi:\n  Ad Soyad: '+(w.owner||'-')+'\n  Organizasyon: '+(w.org||'-')+'\n  E-posta: '+(w.email||'-')+'\n  Telefon: '+(w.phone||'-')+'\n  Ülke: '+(w.country||'-')+'\n  Şehir: '+(w.city||'-')+'\n\nTarihler:\n  Kayıt: '+(w.created||'-')+'\n  Güncelleme: '+(w.updated||'-')+'\n  Bitiş: '+(w.expires||'-')+'\n  Domain Yaşı: '+(w.age||'-')+'\n  Kalan Gün: '+(w.remaining||'-');if(w.nameservers&&w.nameservers.length)whoisTxt+='\n\nDNS Sunucuları: '+w.nameservers.join(', ');if(w.status&&w.status.length)whoisTxt+='\n\nRDAP Durum: '+w.status.join(', ');}document.getElementById('icaWhois').textContent=whoisTxt||'Veri yok.';_icaData.whois=whoisTxt;document.getElementById('icaWhoisDlBtn').disabled=!whoisTxt;
var active=d.subs&&d.subs.active?d.subs.active:[];var passive=d.subs&&d.subs.passive?d.subs.passive:[];document.getElementById('icaSubActiveCount').textContent=active.length;document.getElementById('icaSubPassiveCount').textContent=passive.length;if(active.length){var ah='';for(var i=0;i<active.length;i++){var s=active[i];ah+='<tr><td class="fw-bold"><a href="http://'+s.h+'" target="_blank" class="text-decoration-none">'+s.h+'</a></td><td><span class="badge bg-primary">'+s.i+'</span></td><td><a href="http://'+s.h+'" target="_blank">Aç</a></td></tr>';}document.getElementById('icaSubActiveBody').innerHTML=ah;}else{document.getElementById('icaSubActiveBody').innerHTML='<tr><td colspan="3" class="text-center text-muted py-2">Aktif kayıt yok</td></tr>';}
