_icaRevList=d.rev||[];document.getElementById('icaRevSummary').textContent='Bu sunucuda '+d.rev_total+' domain barındırılıyor.';document.getElementById('icaRevDlBtn').disabled=_icaRevList.length===0;if(_icaRevList.length){var rh='';for(var i=0;i<_icaRevList.length;i++){rh+='<div class="list-group-item py-1"><a href="http://'+_icaRevList[i]+'" target="_blank" class="fw-bold text-decoration-none">'+_icaRevList[i]+'</a></div>';}document.getElementById('icaRevList').innerHTML=rh;}else{document.getElementById('icaRevList').innerHTML='<div class="list-group-item text-muted text-center py-2">Reverse IP sonucu yok</div>';}
