function downloadIcaRevList(){if(!_icaRevList.length)return;var domain=document.getElementById('icaDomain').value.replace(/[^a-z0-9._-]/gi,'_')||'liste';var txt='';for(var i=0;i<_icaRevList.length;i++){txt+='https://'+_icaRevList[i]+'\r\n';}var blob=new Blob([txt],{type:'text/plain;charset=utf-8'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='reverse-ip-'+domain+'.txt';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);a.remove();},500);}
