function downloadIcaDns(){var dns=_icaData.dns||[];if(!dns.length)return;var domain=document.getElementById('icaDomain').value.replace(/[^a-z0-9._-]/gi,'_')||'dns';var txt='# DNS KAYITLARI\r\n# Domain: '+_icaData.domain+'\r\n\r\n';for(var i=0;i<dns.length;i++){var r=dns[i];var rtype=r.type||'-';var rval=r.target||r.ip||r.txt||r.ipv6||r.pri||'-';if(r.type==='MX')rval=(r.pri||'')+' '+r.target;txt+=rtype+'\t'+rval+'\r\n';}var blob=new Blob([txt],{type:'text/plain;charset=utf-8'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='dns-'+domain+'.txt';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);a.remove();},500);}
