function downloadIcaAll(){var domain=document.getElementById('icaDomain').value.replace(/[^a-z0-9._-]/gi,'_')||'bilgi';var txt='#######################################\r\n# BILGI TOPLAMA RAPORU\r\n# Domain: '+_icaData.domain+'\r\n#######################################\r\n\r\n';txt+='\r\n========================================\r\n# GENEL BILGILER\r\n========================================\r\n';txt+=_icaData.genel||'Veri yok.';txt+='\r\n\r\n========================================\r\n# SUBDOMAIN SONUCLARI\r\n========================================\r\n';var active=_icaData.subs.active||[];var passive=_icaData.subs.passive||[];txt+='\r\n## AKTIF ('+active.length+')\r\n';for(var i=0;i<active.length;i++){txt+='https://'+active[i].h+' - IP: '+active[i].i+'\r\n';}txt+='\r\n## PASIF ('+passive.length+')\r\n';for(var i=0;i<passive.length;i++){txt+='https://'+passive[i].h+'\r\n';}txt+='\r\n\r\n========================================\r\n# REVERSE IP\r\n========================================\r\n';txt+='Toplam: '+_icaRevList.length+' domain\r\n\r\n';for(var i=0;i<_icaRevList.length;i++){txt+='https://'+_icaRevList[i]+'\r\n';}txt+='\r\n\r\n========================================\r\n# DNS KAYITLARI\r\n========================================\r\n';var dns=_icaData.dns||[];for(var i=0;i<dns.length;i++){var r=dns[i];var rtype=r.type||'-';var rval=r.target||r.ip||r.txt||r.ipv6||r.pri||'-';if(r.type==='MX')rval=(r.pri||'')+' '+r.target;txt+=rtype+'\t'+rval+'\r\n';}txt+='\r\n\r\n========================================\r\n# WHOIS BILGILERI\r\n========================================\r\n';txt+=_icaData.whois||'Veri yok.';var blob=new Blob([txt],{type:'text/plain;charset=utf-8'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='bilgi-toplama-'+domain+'.txt';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);a.remove();},500);}
function clearAllSelectedFiles(){selectedFilesList=[];var inp=document.getElementById('uploadFiles');if(inp)inp.value='';renderFileList();}
function renderFileList(){var container=document.getElementById('selectedFiles');if(!container)return; if(selectedFilesList.length===0){container.innerHTML='';return;}var html='';for(var i=0;i<selectedFilesList.length;i++){var f=selectedFilesList[i];var size=f.size<1024?f.size+' B':f.size<1048576?(f.size/1024).toFixed(1)+' KB':(f.size/1048576).toFixed(1)+' MB';html+='<div class="file-list-item"><span title="'+f.name+'">'+f.name+'</span><span class="file-size">'+size+'</span><i class="bi bi-x-circle remove-file" onclick="removeFile('+i+')"></i></div>';}container.innerHTML=html;}
